targets.query:
from(bucket: "robot")
  |> range(start: -1h)
  |> filter(fn: (r) => r._measurement == "wheel_state")
  |> filter(fn: (r) => r._field == "pwm_override_enable")
  |> filter(fn: (r) => r.wheel_side == "left")
  |> map(fn: (r) => ({
      r with _value: if r._value then 0 else 1
  }))

resetAction.code:
fetch("http://localhost:5000/command/motion", {
  method: "POST",
  headers: {
    "Content-Type": "application/json"
  },
  body: JSON.stringify({
    speed: 1.2,
    omega: 0.5
  })
})
  .then(response => response.json())

